Here's a modern MSTest approach covering async tests, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Async tests: return Task, MSTest awaits them natively
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // [Timeout] sets a per-test deadline in ms — catches hangs
    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Verify cancellation is respected
    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancellation()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Verify non-success status codes throw
    [TestMethod]
    public async Task FetchAsync_ThrowsOnNonSuccessStatus()
    {
        var handler = new MockHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal HttpMessageHandler stub — no mocking library needed
    private sealed class MockHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;

        public MockHandler(HttpResponseMessage response) =>
            _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | Return `Task`, use `async/await` — no `.Result` or `.Wait()` |
| **Timeouts** | `[Timeout(ms)]` attribute — MSTest cancels via `TestContext.CancellationTokenSource` |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **HttpClient testing** | Stub `HttpMessageHandler` directly — avoids mocking library overhead |

> **Avoid** `[Timeout]` on every test — reserve it for tests where hangs are a real risk. MSTest also supports a global timeout via `.runsettings` if needed.
